#include <stdio.h>
#include <string.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        char S[100005]; scanf("%s", S);
        int c0=0, c1=0;
        for(int i=0;i<N;i++){
            if(S[i]=='0') c0++; else c1++;
        }
        int ans = (c0==c1) ? N : 2* (c0<c1?c0:c1) + 1;
        if(ans > N) ans = N;
        printf("%d\n", ans);
    }
    return 0;
}

