const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let idx = 0;
const T = Number(input[idx++]);
let results = [];
for (let tc = 0; tc < T; tc++) {
  const N = Number(input[idx++]);
  const S = input[idx++];
  let c0 = 0, c1 = 0;
  for (let ch of S) {
    if (ch === '0') c0++; else c1++;
  }
  let ans = (c0 === c1) ? N : 2 * Math.min(c0, c1) + 1;
  if (ans > N) ans = N;
  results.push(String(ans));
}
